import React, { useRef, useState } from 'react';
import { formatDate, diffDays } from '../data/bookingStore.js';
import styles from '../styles/BookingSummary.module.css';

// ── Constants ─────────────────────────────────────────────────────────────────

export const MAX_GUESTS      = 25;
export const EXTRA_PER_HEAD  = 250;   // ₱ per head beyond MAX_GUESTS

export const BOOKING_TYPES = [
  {
    id: 'day-use',
    icon: '☀️',
    name: 'Day Use',
    description: '8:00 AM – 8:00 PM',
    weekdayPrice: 8000,
    weekendPrice: 10000,
  },
  {
    id: 'overnight',
    icon: '🌙',
    name: 'Overnight',
    description: '3:00 PM – 11:00 AM',   // ← fixed: was 2:00 PM
    weekdayPrice: 10000,
    weekendPrice: 13000,
  },
];

export const INCLUSIONS = [
  { icon: '🏡', label: 'Exclusive use of the resort' },
  { icon: '🛏️', label: 'Five Rooms' },
  { icon: '📶', label: 'Wi-Fi' },
  { icon: '🍳', label: 'Restaurant Kitchen' },
  { icon: '🚿', label: '2 Showers & 3 Bathrooms' },
  { icon: '🌡️', label: 'Hot & cold shower' },
  { icon: '💧', label: 'Water dispenser (3 free gallons)' },
  { icon: '📺', label: 'TV & speaker' },
  { icon: '🔥', label: 'Bonfire setup (2 packs firewood)' },
  { icon: '⚡', label: 'Generator set standby' },
  { icon: '🚗', label: 'Gated parking (10–12 cars)' },
  { icon: '🏞️', label: 'Direct access to the river' },
];

// ── Weekend logic: Friday (5), Saturday (6), Sunday (0) ──────────────────────
export const isWeekend = (dateStr) => {
  if (!dateStr) return false;
  const day = new Date(dateStr + 'T00:00:00').getDay();
  return day === 5 || day === 6 || day === 0;  // Fri / Sat / Sun
};

// ── BookingSummary ────────────────────────────────────────────────────────────

const BookingSummary = ({
  checkIn, checkOut, bookingType, setBookingType,
  guests, guestName, guestContact, contactMethod,
  onSubmit,
  // Receipt upload props (pass from parent / store)
  onReceiptUpload,   // fn(bookingId, file) — parent handles persistence
  bookingId,         // set after reservation is confirmed
}) => {
  const fileInputRef = useRef(null);
  const [receiptPreview,  setReceiptPreview]  = useState(null);   // data-URL for preview
  const [receiptUploaded, setReceiptUploaded] = useState(false);
  const [uploadError,     setUploadError]     = useState('');

  // ── Pricing ────────────────────────────────────────────────────────────────
  const nights       = checkIn && checkOut ? diffDays(checkIn, checkOut) : 0;
  const weekend      = isWeekend(checkIn);
  const selected     = BOOKING_TYPES.find(t => t.id === bookingType) || null;
  const ratePerNight = selected ? (weekend ? selected.weekendPrice : selected.weekdayPrice) : 0;
  const units        = nights > 0 ? nights : 1;
  const baseTotal    = ratePerNight * units;

  // Extra pax charge (guests beyond MAX_GUESTS at ₱250/head)
  const extraPax      = Math.max(0, (guests || 0) - MAX_GUESTS);
  const extraPaxTotal = extraPax * EXTRA_PER_HEAD;
  const grandTotal    = baseTotal + extraPaxTotal;

  const canSubmit = checkIn && bookingType && guests > 0
    && guestName.trim() && guestContact.trim();

  // For Day-Use multi-day: last day
  const dayUseLastDay = checkOut && nights > 0 ? checkOut : null;

  // ── Receipt upload handler ─────────────────────────────────────────────────
  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const allowed = ['image/jpeg', 'image/png', 'image/webp', 'application/pdf'];
    if (!allowed.includes(file.type)) {
      setUploadError('Please upload a JPG, PNG, WEBP, or PDF file.');
      return;
    }
    if (file.size > 10 * 1024 * 1024) {
      setUploadError('File too large. Maximum size is 10 MB.');
      return;
    }

    setUploadError('');

    // Show preview for images
    if (file.type.startsWith('image/')) {
      const reader = new FileReader();
      reader.onload = (ev) => setReceiptPreview(ev.target.result);
      reader.readAsDataURL(file);
    } else {
      setReceiptPreview(null);   // PDF — no preview, just show filename
    }

    setReceiptUploaded(false);

    // Persist via parent callback (parent saves to booking record → admin sees it)
    if (onReceiptUpload) {
      Promise.resolve(onReceiptUpload(bookingId, file))
        .then(() => setReceiptUploaded(true))
        .catch(() => setUploadError('Upload failed. Please try again.'));
    } else {
      // Fallback: mark uploaded locally (demo / no parent handler)
      setReceiptUploaded(true);
    }
  };

  // ── Render ─────────────────────────────────────────────────────────────────
  return (
    <aside className={styles.panel}>
      <div className={styles.panelHeader}>
        <span className={styles.kanjiSmall}>予約</span>
        <h2 className={styles.panelTitle}>Booking Summary</h2>
      </div>

      <div className={styles.panelBody}>
        {!checkIn && (
          <p className={styles.hint}>Select your check-in date on the calendar to begin.</p>
        )}

        {checkIn && (
          <div className={styles.datesBlock}>
            <div className={styles.dateItem}>
              <span className={styles.dateLabel}>
                {bookingType === 'overnight' ? 'Check-in' : 'Date'}
              </span>
              <span className={styles.dateValue}>{formatDate(checkIn)}</span>
              <span className={styles.dateTime}>
                {selected ? selected.description : 'Select a booking type below'}
              </span>
            </div>

            {/* Overnight: nights divider + check-out */}
            {bookingType === 'overnight' && checkOut && nights > 0 && (
              <React.Fragment>
                <div className={styles.dateDivider}>
                  <span className={styles.nightsTag}>
                    {nights} night{nights !== 1 ? 's' : ''}
                  </span>
                </div>
                <div className={styles.dateItem}>
                  <span className={styles.dateLabel}>Check-out</span>
                  <span className={styles.dateValue}>{formatDate(checkOut)}</span>
                  <span className={styles.dateTime}>11:00 AM</span>
                </div>
              </React.Fragment>
            )}

            {/* Day Use: duration pill */}
            {bookingType === 'day-use' && (
              <div className={styles.dateDivider}>
                <span className={styles.nightsTag}>
                  {units > 1 ? (units + ' days · Day Use') : '12 hrs · Day Use'}
                </span>
              </div>
            )}

            {/* Day Use multi-day: last day */}
            {bookingType === 'day-use' && dayUseLastDay && (
              <div className={styles.dateItem}>
                <span className={styles.dateLabel}>Last Day</span>
                <span className={styles.dateValue}>{formatDate(dayUseLastDay)}</span>
                <span className={styles.dateTime}>8:00 AM – 8:00 PM</span>
              </div>
            )}
          </div>
        )}

        {/* Booking type selector */}
        <div className={styles.typeRow}>
          {BOOKING_TYPES.map(t => (
            <button
              key={t.id}
              type="button"
              className={styles.typeBtn + (bookingType === t.id ? ' ' + styles.typeBtnActive : '')}
              onClick={() => setBookingType(t.id)}
            >
              <span className={styles.typeIcon}>{t.icon}</span>
              <span className={styles.typeName}>{t.name}</span>
              <span className={styles.typeDesc}>{t.description}</span>
            </button>
          ))}
        </div>

        {/* Guest info summary */}
        {(guestName.trim() || guests > 0) && (
          <div className={styles.guestBlock}>
            {guestName.trim() && (
              <div className={styles.guestRow}>
                <span className={styles.guestLabel}>Guest</span>
                <span className={styles.guestValue}>{guestName}</span>
              </div>
            )}
            {guests > 0 && (
              <div className={styles.guestRow}>
                <span className={styles.guestLabel}>Pax</span>
                <span className={styles.guestValue}>
                  {guests} {guests === 1 ? 'person' : 'persons'}
                  {guests > MAX_GUESTS && (
                    <span className={styles.extraPaxNote}>
                      {' '}(+{extraPax} extra @ ₱{EXTRA_PER_HEAD.toLocaleString()}/head)
                    </span>
                  )}
                </span>
              </div>
            )}
            <div className={styles.guestRow}>
              <span className={styles.maxNote}>Max {MAX_GUESTS} guests included</span>
            </div>
            {guestContact.trim() && (
              <div className={styles.guestRow}>
                <span className={styles.guestLabel}>
                  {contactMethod === 'email' ? 'Email' : 'Messenger'}
                </span>
                <span className={styles.guestValue}>{guestContact}</span>
              </div>
            )}
          </div>
        )}

        {/* Price breakdown */}
        {selected && checkIn && (
          <div className={styles.priceBlock}>
            <div className={styles.priceRow}>
              <span>{weekend ? 'Weekend' : 'Weekday'} rate</span>
              <span>{'₱' + ratePerNight.toLocaleString()}</span>
            </div>

            {bookingType === 'overnight' && (
              <div className={styles.priceRow}>
                <span>{'× ' + units + ' night' + (units !== 1 ? 's' : '')}</span>
                <span>{'₱' + baseTotal.toLocaleString()}</span>
              </div>
            )}

            {bookingType === 'day-use' && (
              <div className={styles.priceRow}>
                <span>{'× ' + units + ' day' + (units !== 1 ? 's' : '') + ' (12 hrs each)'}</span>
                <span>{'₱' + baseTotal.toLocaleString()}</span>
              </div>
            )}

            {/* Extra pax charge */}
            {extraPax > 0 && (
              <div className={styles.priceRow}>
                <span>
                  Extra pax: {extraPax} × ₱{EXTRA_PER_HEAD.toLocaleString()}
                </span>
                <span>{'₱' + extraPaxTotal.toLocaleString()}</span>
              </div>
            )}

            <div className={styles.priceRow + ' ' + styles.totalRow}>
              <span>Total</span>
              <span>{'₱' + grandTotal.toLocaleString()}</span>
            </div>
            <p className={styles.pricingNote}>VAT inclusive · Pay upon arrival</p>
          </div>
        )}

        {/* ── QR Code Payment Section ──────────────────────────────────────── */}
        <div className={styles.qrSection}>
          <div className={styles.qrHeader}>
            <span className={styles.qrTitle}>💳 Pay via GCash / Maya</span>
            <p className={styles.qrSubtitle}>
              Scan the QR code below to send your payment, then upload your receipt.
            </p>
          </div>

          {/* QR Code image — replace src with your actual hosted QR image URL */}
          <div className={styles.qrImageWrap}>
            <img
              src="/images/payment-qr.png"
              alt="GCash / Maya QR Code"
              className={styles.qrImage}
              onError={(e) => {
                // Fallback placeholder if image path not yet set
                e.currentTarget.style.display = 'none';
                e.currentTarget.nextSibling.style.display = 'flex';
              }}
            />
            {/* Fallback placeholder shown if image fails to load */}
            <div className={styles.qrPlaceholder} style={{ display: 'none' }}>
              <span className={styles.qrPlaceholderIcon}>📱</span>
              <span className={styles.qrPlaceholderText}>QR Code</span>
              <span className={styles.qrPlaceholderHint}>
                Place your payment QR image at<br />/public/images/payment-qr.png
              </span>
            </div>
          </div>

          {/* Upload Receipt button */}
          <div className={styles.receiptSection}>
            <p className={styles.receiptLabel}>After payment, upload your receipt:</p>

            <input
              ref={fileInputRef}
              type="file"
              accept="image/jpeg,image/png,image/webp,application/pdf"
              className={styles.hiddenFileInput}
              onChange={handleFileChange}
              aria-label="Upload payment receipt"
            />

            <button
              type="button"
              className={
                styles.receiptBtn +
                (receiptUploaded ? ' ' + styles.receiptBtnDone : '')
              }
              onClick={() => fileInputRef.current?.click()}
            >
              {receiptUploaded
                ? '✅ Receipt Uploaded'
                : '📤 Upload Receipt'}
            </button>

            {uploadError && (
              <p className={styles.receiptError}>{uploadError}</p>
            )}

            {/* Image preview thumbnail */}
            {receiptPreview && (
              <div className={styles.receiptPreviewWrap}>
                <img
                  src={receiptPreview}
                  alt="Receipt preview"
                  className={styles.receiptPreview}
                />
                {receiptUploaded && (
                  <span className={styles.receiptSentBadge}>
                    Sent to admin ✓
                  </span>
                )}
              </div>
            )}

            {/* PDF: no image preview, just filename */}
            {receiptUploaded && !receiptPreview && (
              <p className={styles.receiptFileName}>
                ✓ File received — admin will review your receipt.
              </p>
            )}
          </div>
        </div>
        {/* ── End QR Section ──────────────────────────────────────────────── */}
      </div>

      <div className={styles.panelFooter}>
        <button
          className={styles.cta}
          disabled={!canSubmit}
          onClick={onSubmit}
          type="button"
        >
          <span className={styles.ctaText}>Confirm Reservation</span>
          <span className={styles.ctaArrow}>→</span>
        </button>
        {!canSubmit && (
          <p className={styles.ctaNote}>
            {!checkIn      ? 'Select a date'
            : !bookingType ? 'Choose Day Use or Overnight'
            : 'Complete your details'}
          </p>
        )}
      </div>
    </aside>
  );
};

export default BookingSummary;
